  {id:1564, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Máy phát điện đài STAR 2000 vận hành ở chế độ AUTO có nghĩa là:", options:["Máy phát điện  được đặt ở chế độ AUTO", "ATS Lưới-Máy phát ở chế độ AUTO, ATS MF-MF ở chế độ AUTO.", "ATS Lưới-Máy phát ở chế độ AUTO, ATS MF-MF ở chế độ AUTO, cả hai máy phát điện được đặt ở chế độ AUTO."], correctAnswer:"ATS Lưới-Máy phát ở chế độ AUTO, ATS MF-MF ở chế độ AUTO, cả hai máy phát điện được đặt ở chế độ AUTO.", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1565, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Tại màn hình giám sát nguồn đài STAR 2000, màn hình \\\"OVERVIEW\\\" có chức năng gì?", options:["Xem tổng quát điện áp, dòng điện tiêu thụ của radar STAR 2000", "Xem tổng quát sơ đồ hệ thống sẽ điều khiển, giám sát và điều khiển tất cả các MCCB, đọc các thông số đo của UPS, máy phát,…", "Điều khiển các ATS Lưới-MP, MP-MP, tắt mở điện các vị trí."], correctAnswer:"Xem tổng quát sơ đồ hệ thống sẽ điều khiển, giám sát và điều khiển tất cả các MCCB, đọc các thông số đo của UPS, máy phát,…", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1566, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Tại trang OVERVIEW màn hình  giám sát nguồn đài STAR 2000, để xem đồ thị các thông số về điện áp, dòng diện, công suất….của UPS1 hoặc UPS2 thì làm như thế nào?", options:["Không thể xem được tại trang OVERVIEW.", "Phải vào trang của UPS mới xem được.", "Tại trang OVERVIEW, nhấn chuột vào ô có chữ \\\"UPS1 TREND\\\" hoặc \\\"UPS2 TREND\\\"."], correctAnswer:"Tại trang OVERVIEW, nhấn chuột vào ô có chữ \\\"UPS1 TREND\\\" hoặc \\\"UPS2 TREND\\\".", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1567, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Tại trang OVERVIEW màn hình  giám sát nguồn đài STAR 2000, để xem đồ thị các thông số về điện áp, dòng diện, công suất… của máy phát điện 1 hoặc máy phát điện 2 thì làm như thế nào?", options:["Không thể xem được tại trang OVERVIEW.", "Phải vào trang của máy phát điện mới xem được.", "Tại trang OVERVIEW, nhấn chuột vào ô có chữ \\\"Generator 1 TREND\\\" hoặc \\\"Generator 2 TREND\\\"."], correctAnswer:"Tại trang OVERVIEW, nhấn chuột vào ô có chữ \\\"Generator 1 TREND\\\" hoặc \\\"Generator 2 TREND\\\".", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1568, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Tại trang MV màn hình  giám sát nguồn đài STAR 2000, người khai thác có thể xem được những gì?", options:["Xem được điện áp chính (Main Voltage) của hệ thống điện.", "Xem được trạng thái đóng cắt của các dao cắt, dao tiếp địa các tuyến trung thế; nhiệt độ máy biến áp; trạng thái cầu chì và một số các tham số của dòng, áp ba pha."], correctAnswer:"Xem được trạng thái đóng cắt của các dao cắt, dao tiếp địa các tuyến trung thế; nhiệt độ máy biến áp; trạng thái cầu chì và một số các tham số của dòng, áp ba pha.", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1569, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Trên màn hình giám sát nguồn đài STAR 2000 nói chung, khi một dao cắt/CB ở trạng thái đóng được hiển thị bằng màu gì?", options:["Màu xanh lá", "Màu đỏ", "Thay đổi giữa các màu xanh lá/đỏ."], correctAnswer:"Màu đỏ", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1570, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Tại trang UPS màn hình  giám sát nguồn đài STAR 2000, người khai thác có thể xem được những gì?", options:["Xem được UPS nào đang hoạt động chính.", "Xem được trạng thái hoạt động của các MCCB đầu vào và ra của UPS; thông số về điện áp, dòng điện, công suất của 2 UPS."], correctAnswer:"Xem được trạng thái hoạt động của các MCCB đầu vào và ra của UPS; thông số về điện áp, dòng điện, công suất của 2 UPS.", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1571, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Tại trang Generator (máy phát)  màn hình giám sát nguồn đài STAR 2000 có thể xem được những tham số gì?", options:["Tham số máy phát điện.", "Trạng thái đóng cắt của các MCCB có liên quan đến máy phát điện.", "Xem được trạng thái đóng cắt của các MCCB liên quan đến máy phát điện; trạng thái hoạt động của máy phát điện; số giờ hoạt động của máy phát điện."], correctAnswer:"Xem được trạng thái đóng cắt của các MCCB liên quan đến máy phát điện; trạng thái hoạt động của máy phát điện; số giờ hoạt động của máy phát điện.", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1572, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Tủ điện LSVB1 tại đài STAR 2000 có chức năng gì?", options:["Cung cấp điện.", "Cung cấp điện cho toàn đài radar.", "Cung cấp điện cho tất cả các phụ tải sử dụng điện và cấp điện đầu vào đến hai UPS 40KVA của hệ thống thiết bị radar."], correctAnswer:"Cung cấp điện cho tất cả các phụ tải sử dụng điện và cấp điện đầu vào đến hai UPS 40KVA của hệ thống thiết bị radar.", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1573, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Tại trang Report màn hình giám sát nguồn đài STAR 2000, người dùng có thể thực hiện các thao tác gì?", options:["Trang report cung cấp cho người dùng những thông số của máy phát, UPS, Multimeter,… ở những thời gian trước đó", "Trang report cung cấp cho người dùng những thông số của máy phát, UPS, Multimeter,… ở những thời gian trước đó; xuất dữ liệu dưới dạng file excel để lưu trữ.", "Trang report để cung cấp thông tin số giờ hoạt động và nhiên liệu của máy phát điện."], correctAnswer:"Trang report cung cấp cho người dùng những thông số của máy phát, UPS, Multimeter,… ở những thời gian trước đó; xuất dữ liệu dưới dạng file excel để lưu trữ.", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"},
  {id:1574, module:"KipTruong-TSN", moduleName:"Kíp trưởng CNS Tân Sơn Nhất", question:"Khi vận hành tủ điện LSVB2 đài STAR 2000 cần lưu ý điều gì quan trọng nhất?", options:["Vận hành khai thác bình thường.", "Không có gì quan trọng.", "Không được đóng cả hai MCCB 4 và MCCB 5 cùng lúc."], correctAnswer:"Không được đóng cả hai MCCB 4 và MCCB 5 cùng lúc.", refDoc:"TongHop-TN-KipTruongCNS-rdTSN.xlsx"}
